#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    cin>>t;
    for(int k=0;k<t;k++){
        int n,m,p=0;
        cin>>n>>m;
        vector<string> b(n);
        for(int i=0;i<n;i++){
            cin>>b[i];
        }
        for(int i=0;i<=n-4;i++){
            for(int j=0;j<=m-4;j++){
                bool c=b[i][j]=='0'&&b[i][j+1]=='0'&&b[i][j+2]=='0'&&b[i][j+3]=='0';
                bool d=b[i+3][j]=='0'&&b[i+3][j+1]=='0'&&b[i+3][j+2]=='0'&&b[i+3][j+3]=='0';
                bool e=b[i+1][j]=='0'&&b[i+1][j+1]=='1'&&b[i+1][j+2]=='1'&&b[i+1][j+3]=='0';
                bool f=b[i+2][j]=='0'&&b[i+2][j+1]=='1'&&b[i+2][j+2]=='1'&&b[i+2][j+3]=='0';
                if(c&&d&&e&&f){
					p=1;
					break;
				}
            }
            if(p==1){
                break;
            }
        }
        if(p==0){
            cout<<"No"<<endl;
        }
        else{
			cout<<"Yes"<<endl;
		}
    }
    return 0;
}
